class Solution {
public:
    int minSwaps(string s) {
        int count = 0;
        for (char c : s) {
            if (c == ']') {
                if (count == 0) {
                    count = 1;
                } else {
                    count--;
                }
            } else {
                count++;
            }
        }
        return count / 2;
    }
};
